+pub(crate) fn py_dict_to_attr_map(attrs: &Bound<'_, PyDict>) -> PyResult<AttrMap> {
+    let mut rust_attrs = AttrMap::new();
+    for (k, v) in attrs.iter() {
+        let key: String = k.extract()?;
+        rust_attrs.insert(key, v.str()?.to_string());
+    }
+    Ok(rust_attrs)
+}
